    23	public class ConditionalMana extends Mana implements Serializable, Emptiable {
    24	
    25	    /**
    26	     * Conditions that should be met (all or any depending on comparison scope)
    27	     * to allow spending {@link Mana} mana.
    28	     */
    29	    private List<Condition> conditions = new ArrayList<>();
    30	
    31	    /**
    32	     * Text displayed as a description for conditional mana. Usually includes
    33	     * the conditions that should be met to use this mana.
    34	     */
    35	    protected String staticText = "Conditional mana.";
