    57	        super(conditionalMana);
    58	        conditions.addAll(conditionalMana.conditions);
    59	        scope = conditionalMana.scope;
    60	        staticText = conditionalMana.staticText;
    61	        manaProducerId = conditionalMana.manaProducerId;
    62	        manaProducerOriginalId = conditionalMana.manaProducerOriginalId;
    63	    }
