    77	    public boolean apply(Ability ability, Game game, UUID manaProducerId, Cost costToPay) {
    78	        if (conditions.isEmpty()) {
    79	            throw new IllegalStateException("Conditional mana should contain at least one Condition");
    80	        }
    81	        for (Condition condition : conditions) {
    82	            boolean applied = (condition instanceof ManaCondition)
    83	                    ? ((ManaCondition) condition).apply(game, ability, manaProducerId, costToPay) : condition.apply(game, ability);
    84	
    85	            if (!applied) {
    86	                // if one condition fails, return false only if All conditions should be met
    87	                // otherwise it may happen that Any other condition will be ok
    88	                if (scope == Filter.ComparisonScope.All) {
    89	                    return false;
    90	                }
    91	            } else {
    92	                // if one condition succeeded, return true only if Any conditions should be met
    93	                // otherwise it may happen that any other condition will fail
    94	                if (scope == Filter.ComparisonScope.Any) {
    95	                    return true;
    96	                }
    97	            }
    98	        }
    99	        // we are here
   100	        // if All conditions should be met, then it's Ok (return true)
   101	        // if Any, then it should have already returned true, so returning false here
   102	        return scope == Filter.ComparisonScope.All;
   103	    }
