   241	        if (!super.equals(o)) {
   242	            return false;
   243	        }
   244	        ConditionalMana that = (ConditionalMana) o;
   245	
   246	        if (!Objects.equals(this.staticText, that.staticText)) {
   247	            return false;
   248	        }
   249	        if (!Objects.equals(this.manaProducerId, that.manaProducerId)) {
   250	            return false;
   251	        }
   252	        if (!Objects.equals(this.manaProducerOriginalId, that.manaProducerOriginalId)) {
   253	            return false;
   254	        }
   255	        if (!Objects.equals(this.scope, that.scope)) {
   256	            return false;
   257	        }
   258	        if (this.conditions == null || that.conditions == null
   259	                || this.conditions.size() != that.conditions.size()) {
   260	            return false;
   261	        }
   262	        for (int i = 0; i < this.conditions.size(); i++) {
   263	            if (!(Objects.equals(this.conditions.get(i), that.conditions.get(i)))) {
   264	                return false;
   265	            }
   266	        }
   267	
   268	        return true;
   269	    }
