package org.mage.test.cards.mana.conditional;

import mage.constants.PhaseStep;
import mage.constants.Zone;
import org.junit.Test;
import org.mage.test.serverside.base.CardTestPlayerBase;

/**
 * @author not yet determined
 */
public class JeganthaTheWellspringTest extends CardTestPlayerBase {

    // Test that Jegantha mana can be used to pay colored costs when
    // regular (non-conditional) mana is available for generic costs.
    // For example, casting Honden of Infinite Rage (2R) with 2 Mountains
    // and Jegantha should work: Mountains pay 2, Jegantha pays R.
    @Test
    public void testJeganthaWithMountainsCastSpell() {
        setStrictChooseMode(true);

        // Jegantha, the Wellspring - {T}: Add {W}{U}{B}{R}{G}. This mana can't be spent to pay generic mana costs.
        addCard(Zone.BATTLEFIELD, playerA, "Jegantha, the Wellspring", 1);
        addCard(Zone.BATTLEFIELD, playerA, "Mountain", 2);

        // Honden of Infinite Rage - {2}{R}
        addCard(Zone.HAND, playerA, "Honden of Infinite Rage", 1);

        castSpell(1, PhaseStep.PRECOMBAT_MAIN, playerA, "Honden of Infinite Rage");

        setStopAt(1, PhaseStep.BEGIN_COMBAT);
        execute();

        assertPermanentCount(playerA, "Honden of Infinite Rage", 1);
    }

    // Alternative scenario: float the mana first, then cast
    @Test
    public void testJeganthaFloatManaThenCast() {
        setStrictChooseMode(true);

        addCard(Zone.BATTLEFIELD, playerA, "Jegantha, the Wellspring", 1);
        addCard(Zone.BATTLEFIELD, playerA, "Mountain", 2);

        addCard(Zone.HAND, playerA, "Honden of Infinite Rage", 1);

        // Float mana from Jegantha
        activateManaAbility(1, PhaseStep.PRECOMBAT_MAIN, playerA, "{T}: Add {W}{U}{B}{R}{G}");
        // Float mana from Mountains
        activateManaAbility(1, PhaseStep.PRECOMBAT_MAIN, playerA, "{T}: Add {R}");
        activateManaAbility(1, PhaseStep.PRECOMBAT_MAIN, playerA, "{T}: Add {R}");

        castSpell(1, PhaseStep.PRECOMBAT_MAIN, playerA, "Honden of Infinite Rage");

        setStopAt(1, PhaseStep.BEGIN_COMBAT);
        execute();

        assertPermanentCount(playerA, "Honden of Infinite Rage", 1);
    }
}

