            payingPlayer.restoreState(bookmark, ability.getRule(), game);
        }
        return false;
    }

    private void handlePhyrexianManaCosts(Ability abilityToPay, Player payingPlayer, Ability source, Game game) {
        if (this.isEmpty()) {
